package com.promoit.otp.controller;
import com.promoit.otp.model.AuthUser;import com.promoit.otp.service.OtpService;import jakarta.servlet.http.HttpServletRequest;import org.springframework.web.bind.annotation.*;
@RestController@RequestMapping("/api/user/otp")
public class UserController{private final OtpService otp;public UserController(OtpService otp){this.otp=otp;}@PostMapping("/generate")public MessageResponse generate(@RequestBody OtpGenerateRequest r,HttpServletRequest req){AuthUser u=(AuthUser)req.getAttribute("authUser");otp.generate(u,r.operationId(),r.email(),r.phone(),r.telegramDestination(),r.sendEmail(),r.sendSms(),r.sendTelegram(),r.saveToFile());return new MessageResponse("otp generated and sent/saved");}@PostMapping("/validate")public MessageResponse validate(@RequestBody OtpValidateRequest r,HttpServletRequest req){AuthUser u=(AuthUser)req.getAttribute("authUser");return new MessageResponse(otp.validate(u,r.operationId(),r.code())?"valid":"invalid");}}
